import React from 'react';
import './Sidebar.css';

const NAV_ITEMS = [
  { icon: '▦', label: 'Dashboard', active: false },
  { icon: '◈', label: 'Planning', active: true },
  { icon: '◎', label: 'Analytics', active: false },
  { icon: '⊞', label: 'Reports', active: false },
  { icon: '⚙', label: 'Settings', active: false },
];

export const Sidebar: React.FC = () => (
  <aside className="sidebar">
    <div className="sidebar__logo">
      <span className="sidebar__logo-mark">C</span>
    </div>
    <nav className="sidebar__nav">
      {NAV_ITEMS.map((item) => (
        <button
          key={item.label}
          className={`sidebar__nav-item ${item.active ? 'sidebar__nav-item--active' : ''}`}
          title={item.label}
        >
          <span className="sidebar__icon">{item.icon}</span>
        </button>
      ))}
    </nav>
    <div className="sidebar__bottom">
      <button className="sidebar__nav-item" title="Profile">
        <span className="sidebar__avatar">U</span>
      </button>
    </div>
  </aside>
);
